from functools import wraps
from flask import Flask, session, redirect, url_for, request, flash, render_template_string
from urllib.parse import urlparse, urljoin

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

def is_safe_url(target):
    ref_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))
    return test_url.scheme in ('http', 'https') and ref_url.netloc == test_url.netloc

def get_redirect_target():
    for target in request.args.get('next'), request.referrer:
        if target and is_safe_url(target):
            return target
    return None

def redirect_back(endpoint='index', **kwargs):
    target = get_redirect_target()
    if not target:
        target = url_for(endpoint, **kwargs)
    return redirect(target)

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            next_url = request.url
            return redirect(url_for('login', next=next_url))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
def index():
    return render_template_string('''
        <h1>Home Page</h1>
        {% if session.get('user_id') %}
            <p>Welcome, {{ session.get('username') }}!</p>
            <a href="{{ url_for('logout') }}">Logout</a>
            <br><a href="{{ url_for('dashboard') }}">Dashboard</a>
            <br><a href="{{ url_for('profile') }}">Profile</a>
        {% else %}
            <p>Please <a href="{{ url_for('login') }}">login</a></p>
        {% endif %}
    ''')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if username == 'admin' and password == 'password':
            session['user_id'] = 1
            session['username'] = username
            flash('Login successful!', 'success')
            
            next_page = request.args.get('next')
            if next_page and is_safe_url(next_page):
                return redirect(next_page)
            return redirect(url_for('index'))
        else:
            flash('Invalid credentials', 'error')
    
    return render_template_string('''
        <h1>Login</h1>
        {% with messages = get_flashed_messages(with_categories=true) %}
            {% if messages %}
                {% for category, message in messages %}
                    <p style="color: {{ 'green' if category == 'success' else 'red' }}">{{ message }}</p>
                {% endfor %}
            {% endif %}
        {% endwith %}
        <form method="post">
            <input type="text" name="username" placeholder="Username" required><br>
            <input type="password" name="password" placeholder="Password" required><br>
            <button type="submit">Login</button>
        </form>
        <p>Hint: username: admin, password: password</p>
        <a href="{{ url_for('index') }}">Back to Home</a>
    ''')

@app.route('/logout')
def logout():
    session.clear()
    flash('You have been logged out', 'success')
    return redirect(url_for('index'))

@app.route('/dashboard')
@login_required
def dashboard():
    return render_template_string('''
        <h1>Dashboard</h1>
        <p>Welcome to your dashboard, {{ session.get('username') }}!</p>
        <a href="{{ url_for('index') }}">Home</a>
        <br><a href="{{ url_for('logout') }}">Logout</a>
    ''')

@app.route('/profile')
@login_required
def profile():
    return render_template_string('''
        <h1>Profile</h1>
        <p>User: {{ session.get('username') }}</p>
        <a href="{{ url_for('index') }}">Home</a>
        <br><a href="{{ url_for('logout') }}">Logout</a>
    ''')

if __name__ == '__main__':
    app.run(debug=True)